    count = 0
    for num in arr:
        if num == 0:
            continue
        s = str(num)
        # handle negative sign: first digit is negative
        if s[0] == '-':
            total = -int(s[1])  # first signed digit negative
            for ch in s[2:]:
                total += int(ch)
        else:
            total = sum(int(ch) for ch in s)
        if total > 0:
            count += 1
    return count
